SELECT

FROM project_orchestration_steps s
INNER JOIN project_orchestration_sessions sess ON sess.id = s.session_id
WHERE sess.project_id = #{project_id}
  AND s.session_id = #{session_id}
  AND s.id = #{id}

SELECT

FROM project_orchestration_steps s
INNER JOIN project_orchestration_sessions sess ON sess.id = s.session_id
WHERE sess.project_id = #{project_id}
  AND s.session_id = #{session_id}
ORDER BY s.sequence_no ASC, s.id ASC

mapper.update:
UPDATE project_orchestration_steps
SET status = #{status, jdbcType=VARCHAR},
    started_at = COALESCE(started_at, #{started_at, jdbcType=TIMESTAMP}),
    completed_at = #{completed_at, jdbcType=TIMESTAMP},
    failure_reason = #{failure_reason},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND session_id = #{session_id}
  AND EXISTS (
    SELECT 1
    FROM project_orchestration_sessions sess
    WHERE sess.id = #{session_id}
      AND sess.project_id = #{project_id}
  )
